func Maxrecord4NextReq(in *proto.TrxRes, params map[string]string, shards int) (*proto.TrxReq, map[string]string, int) {
	hopId := in.Info.Hopid
	req := &proto.TrxReq{Info: in.Info}
	nextShard := 0

	switch hopId {
	case 0:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop0Par(paramsCopy))
	case 1:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop1Par(paramsCopy))
	case 2:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop2Par(paramsCopy))
	case 3:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop3Par(paramsCopy))
	case 4:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop4Par(paramsCopy))
	case 5:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop5Par(paramsCopy))
	case 6:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop6Par(paramsCopy))
	case 7:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop7Par(paramsCopy))
	case 8:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop8Par(paramsCopy))
	case 9:
		// Deep copy params to avoid modification
		paramsCopy := make(map[string]string)
		for k, v := range params {
			paramsCopy[k] = v
		}
		// Calculate partition for next hop using partition function
		nextShard = int(Maxrecord4Hop9Par(paramsCopy))
	default:
		return nil, params, 0
	}

	req.Params = params
	req.Info.Hopid += 1
	req.Dependency = in.Dependency
	return req, params, nextShard
}

